import { useCallback, useEffect, useState } from "react";

const API_BASE = "http://localhost:8086/api";

const ACTIVITIES = [
  "Quiz Completion",
  "Assignment Submission",
  "Session Attendance",
  "Resource Completion",
  "Hackathon / Competition",
  "Custom Activity",
];

function FieldError({ msg }) {
  if (!msg) return null;
  return (
    <p className="mt-1 text-xs text-red-500 flex items-center gap-1">
      ⚠ {msg}
    </p>
  );
}

function inputCls(hasError) {
  return `mt-1 w-full rounded-lg border px-3 py-2 text-sm ${
    hasError
      ? "border-red-400 bg-red-50 focus:ring-1 focus:ring-red-400 focus:outline-none"
      : "border-slate-200 focus:ring-1 focus:ring-violet-400 focus:outline-none"
  }`;
}

export default function AdminCreditPage() {
  const [users, setUsers] = useState([]);
  const [selectedStudent, setSelectedStudent] = useState("");
  const [totalCredits, setTotalCredits] = useState(null);
  const [history, setHistory] = useState([]);
  const [backendStatus, setBackendStatus] = useState("Connecting...");

  const [awardForm, setAwardForm] = useState({
    studentId: "",
    activity: ACTIVITIES[0],
    customActivity: "",
    credits: "",
  });

  const [awardErrors, setAwardErrors] = useState({});
  const [awarding, setAwarding] = useState(false);
  const [editingTx, setEditingTx] = useState(null);
  const [editErrors, setEditErrors] = useState({});

  useEffect(() => {
    fetch(`${API_BASE}/users`)
      .then((r) => (r.ok ? r.json() : []))
      .then((data) => {
        setUsers(data || []);
        if (data?.length > 0) {
          const first = data[0].username || data[0].name || `User #${data[0].id}`;
          setSelectedStudent(first);
          setAwardForm((p) => ({ ...p, studentId: first }));
        } else {
          setSelectedStudent("STU-2026-001");
          setAwardForm((p) => ({ ...p, studentId: "STU-2026-001" }));
        }
        setBackendStatus("Online");
      })
      .catch(() => {
        setSelectedStudent("STU-2026-001");
        setAwardForm((p) => ({ ...p, studentId: "STU-2026-001" }));
        setBackendStatus("Offline");
      });
  }, []);

  useEffect(() => {
    const checkBackend = async () => {
      try {
        const res = await fetch(`${API_BASE}/health`);
        setBackendStatus(res.ok ? "Online" : "Offline");
      } catch {
        setBackendStatus("Offline");
      }
    };

    checkBackend();
    const interval = setInterval(checkBackend, 5000);
    return () => clearInterval(interval);
  }, []);

  const loadStudentData = useCallback(async (studentId) => {
    if (!studentId) return;
    try {
      const [credRes, histRes] = await Promise.all([
        fetch(`${API_BASE}/credits/student/${studentId}`),
        fetch(`${API_BASE}/credits/history/${studentId}`),
      ]);

      if (credRes.ok) {
        const d = await credRes.json();
        setTotalCredits(d.totalCredits ?? 0);
      }

      if (histRes.ok) setHistory(await histRes.json());

      setBackendStatus("Online");
    } catch {
      setBackendStatus("Offline");
    }
  }, []);

  useEffect(() => {
    if (selectedStudent) loadStudentData(selectedStudent);
  }, [selectedStudent, loadStudentData]);

  const studentOptions =
    users.length > 0
      ? users.map((u) => u.username || u.name || `User #${u.id}`)
      : ["STU-2026-001", "STU-2026-002", "STU-2026-003"];

  function handleAwardInput(e) {
    const { name, value } = e.target;
    setAwardForm((p) => ({ ...p, [name]: value }));
  }

  async function handleAward(e) {
    e.preventDefault();
    setAwarding(true);

    try {
      const activity =
        awardForm.activity === "Custom Activity"
          ? awardForm.customActivity
          : awardForm.activity;

      await fetch(`${API_BASE}/credits/award`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          studentId: awardForm.studentId,
          activity,
          credits: parseInt(awardForm.credits, 10),
        }),
      });

      await loadStudentData(selectedStudent);
    } finally {
      setAwarding(false);
    }
  }

  function formatDate(iso) {
    return iso
      ? new Date(iso).toLocaleString()
      : "—";
  }

  return (
    <div className="min-h-screen w-full flex items-center justify-center bg-gradient-to-br from-slate-900 via-gray-900 to-slate-800 relative p-6">

      {/* 🔥 Backdrop overlay */}
      <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" />

      {/* Main Card */}
      <div className="relative w-full max-w-6xl rounded-2xl bg-white shadow-2xl p-6 z-10">

        {/* Header */}
        <div className="mb-6 flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-bold text-violet-900">
              Credit Management
            </h2>
            <p className="text-sm text-slate-500">
              Award credits & manage transactions
            </p>
          </div>

          <span
            className={`px-3 py-1 text-xs rounded-full font-semibold ${
              backendStatus === "Online"
                ? "bg-emerald-100 text-emerald-700"
                : "bg-red-100 text-red-700"
            }`}
          >
            {backendStatus}
          </span>
        </div>

        <div className="grid lg:grid-cols-2 gap-6">

          {/* LEFT: FORM */}
          <form
            onSubmit={handleAward}
            className="bg-violet-50 p-5 rounded-xl space-y-3"
          >
            <h3 className="font-bold text-violet-800">🏅 Award Credits</h3>

            <select
              name="studentId"
              value={awardForm.studentId}
              onChange={handleAwardInput}
              className={inputCls(false)}
            >
              {studentOptions.map((s) => (
                <option key={s}>{s}</option>
              ))}
            </select>

            <select
              name="activity"
              value={awardForm.activity}
              onChange={handleAwardInput}
              className={inputCls(false)}
            >
              {ACTIVITIES.map((a) => (
                <option key={a}>{a}</option>
              ))}
            </select>

            <input
              name="credits"
              type="number"
              placeholder="Credits"
              value={awardForm.credits}
              onChange={handleAwardInput}
              className={inputCls(false)}
            />

            <button
              disabled={awarding}
              className="w-full bg-violet-700 text-white py-2 rounded-lg font-bold hover:bg-violet-800"
            >
              {awarding ? "Awarding..." : "Award Credits"}
            </button>
          </form>

          {/* RIGHT: SUMMARY */}
          <div>
            <div className="bg-slate-50 p-4 rounded-xl mb-4">
              <h3 className="text-sm text-slate-500">Selected Student</h3>
              <select
                value={selectedStudent}
                onChange={(e) => setSelectedStudent(e.target.value)}
                className="w-full mt-2 p-2 border rounded-lg"
              >
                {studentOptions.map((s) => (
                  <option key={s}>{s}</option>
                ))}
              </select>

              {totalCredits !== null && (
                <div className="mt-4 text-center">
                  <p className="text-4xl font-bold text-emerald-600">
                    {totalCredits}
                  </p>
                  <p className="text-xs text-slate-500">Total Credits</p>
                </div>
              )}
            </div>

            <div className="border rounded-xl overflow-hidden">
              <table className="w-full text-sm">
                <thead className="bg-slate-100 text-xs">
                  <tr>
                    <th className="p-2">Activity</th>
                    <th className="p-2">Credits</th>
                    <th className="p-2">Date</th>
                  </tr>
                </thead>
                <tbody>
                  {history.map((tx) => (
                    <tr key={tx.id} className="border-t">
                      <td className="p-2">{tx.activity}</td>
                      <td className="p-2 text-emerald-600 font-bold">
                        +{tx.credits}
                      </td>
                      <td className="p-2 text-xs text-slate-500">
                        {formatDate(tx.awardedAt)}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}
